import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const SEMESTERS = [1,2,3,4,5,6,7,8];
const emptyForm = { name: '', code: '', semester: '', credits: 3, maxMidMarks: 30 };

export default function HodSubjects() {
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState(emptyForm);
  const [saving, setSaving] = useState(false);
  const [semFilter, setSemFilter] = useState('');

  const load = () => {
    const params = semFilter ? { semester: semFilter } : {};
    axios.get('/api/hod/subjects', { params }).then(res => { setSubjects(res.data.subjects); setLoading(false); });
  };
  useEffect(load, [semFilter]);

  const openCreate = () => { setEditing(null); setForm(emptyForm); setModal(true); };
  const openEdit = (s) => { setEditing(s); setForm({ name: s.name, code: s.code, semester: s.semester, credits: s.credits, maxMidMarks: s.maxMidMarks }); setModal(true); };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.code || !form.semester) return toast.error('Name, code and semester are required');
    setSaving(true);
    try {
      if (editing) {
        await axios.put(`/api/hod/subjects/${editing._id}`, form);
        toast.success('Subject updated');
      } else {
        await axios.post('/api/hod/subjects', form);
        toast.success('Subject added successfully');
      }
      setModal(false);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Error saving subject');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (subject) => {
    if (!window.confirm(`Deactivate subject "${subject.name}"?`)) return;
    try {
      await axios.delete(`/api/hod/subjects/${subject._id}`);
      toast.success('Subject deactivated');
      load();
    } catch { toast.error('Failed'); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  const grouped = {};
  subjects.forEach(s => { if (!grouped[s.semester]) grouped[s.semester] = []; grouped[s.semester].push(s); });

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Subject Management</div>
          <div className="page-subtitle">Add and manage subjects for your department</div>
        </div>
        <button className="btn btn-primary" onClick={openCreate}>＋ Add Subject</button>
      </div>

      <div className="filter-bar">
        <select className="form-select" style={{ width: 180 }} value={semFilter} onChange={e => setSemFilter(e.target.value)}>
          <option value="">All Semesters</option>
          {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
        </select>
        <span className="text-muted" style={{ fontSize: 13 }}>{subjects.length} subjects</span>
      </div>

      {subjects.length === 0 ? (
        <div className="card"><div className="empty-state"><div className="empty-icon">📚</div><div className="empty-text">No subjects found</div><div className="empty-subtext">Add subjects for your department</div></div></div>
      ) : (
        Object.keys(grouped).sort((a, b) => Number(a) - Number(b)).map(sem => (
          <div key={sem} className="card mt-16">
            <div className="card-header">
              <span className="card-title">📚 Semester {sem}</span>
              <span className="badge badge-blue">{grouped[sem].length} subjects</span>
            </div>
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr><th>#</th><th>Subject Name</th><th>Code</th><th>Credits</th><th>Max Mid Marks</th><th>Status</th><th>Actions</th></tr>
                </thead>
                <tbody>
                  {grouped[sem].map((s, i) => (
                    <tr key={s._id}>
                      <td>{i + 1}</td>
                      <td className="fw-600">{s.name}</td>
                      <td><span className="badge badge-purple">{s.code}</span></td>
                      <td>{s.credits}</td>
                      <td>{s.maxMidMarks}</td>
                      <td><span className={`badge ${s.isActive ? 'badge-green' : 'badge-red'}`}>{s.isActive ? 'Active' : 'Inactive'}</span></td>
                      <td>
                        <div className="gap-8">
                          <button className="btn btn-outline btn-sm" onClick={() => openEdit(s)}>✏️ Edit</button>
                          {s.isActive && <button className="btn btn-danger btn-sm" onClick={() => handleDelete(s)}>🗑</button>}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ))
      )}

      {modal && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setModal(false)}>
          <div className="modal">
            <div className="modal-header">
              <span className="modal-title">{editing ? '✏️ Edit Subject' : '📚 Add Subject'}</span>
              <button className="modal-close" onClick={() => setModal(false)}>×</button>
            </div>
            <form onSubmit={handleSubmit}>
              <div className="modal-body">
                <div className="form-group">
                  <label className="form-label">Subject Name *</label>
                  <input className="form-input" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="e.g. Data Structures & Algorithms" required />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Subject Code *</label>
                    <input className="form-input" value={form.code} onChange={e => setForm({ ...form, code: e.target.value.toUpperCase() })} placeholder="e.g. CS301" required />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Semester *</label>
                    <select className="form-select" value={form.semester} onChange={e => setForm({ ...form, semester: Number(e.target.value) })} required>
                      <option value="">Select Semester</option>
                      {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
                    </select>
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Credits</label>
                    <input className="form-input" type="number" min={1} max={6} value={form.credits} onChange={e => setForm({ ...form, credits: Number(e.target.value) })} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Max Mid Marks</label>
                    <input className="form-input" type="number" min={10} max={100} value={form.maxMidMarks} onChange={e => setForm({ ...form, maxMidMarks: Number(e.target.value) })} />
                  </div>
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-outline" onClick={() => setModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : editing ? 'Update' : 'Add Subject'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
